import * as crypto from "crypto";
import {
  AdminInitiateAuthCommand,
  CognitoIdentityProviderClient,
} from "@aws-sdk/client-cognito-identity-provider";
import { DynamoDBClient, PutItemCommand } from "@aws-sdk/client-dynamodb";
import { getTenantContext, createResponse } from "tenant-utils";

const validateInputParams = (event) => {
  return (
    event.email.trim().length > 0 &&
    event.password.trim().length > 0 &&
    event.apti.trim().length > 0
  );
};

function makeId(length) {
  var result = "";
  var characters =
    "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
  var charactersLength = characters.length;
  for (var i = 0; i < length; i++) {
    result += characters.charAt(Math.floor(Math.random() * charactersLength));
  }
  return result;
}

const getUserWithPassword = async (
  payload,
  cognito,
  secretHash,
  userPoolId,
  appClientId,
) => {
  return cognito.send(
    new AdminInitiateAuthCommand({
      AuthParameters: {
        USERNAME: payload.email.trim().toLowerCase(),
        PASSWORD: payload.password,
        SECRET_HASH: secretHash,
      },
      UserPoolId: userPoolId,
      ClientId: appClientId,
      AuthFlow: "ADMIN_NO_SRP_AUTH",
    }),
  );
};

const getUser = async (
  payload,
  cognito,
  userPoolId,
  appClientId,
  appSecret,
) => {
  const appclientId = appClientId;
  const appclientSecret = appSecret;

  const secretHash = crypto
    .createHmac("SHA256", appclientSecret)
    .update(payload.email.trim().toLowerCase() + appclientId)
    .digest("base64");

  return getUserWithPassword(
    payload,
    cognito,
    secretHash,
    userPoolId,
    appClientId,
  );
};

const storeTokens = async (
  user,
  payload,
  authCode,
  dynamodb,
  requestTimeEpoch,
  tableNames,
  tenantId,
) => {
  console.log(`[Tenant: ${tenantId}] tokens write user:`, user);
  const tokenString =
    '{"id_token":"' +
    user.AuthenticationResult["IdToken"] +
    '",' +
    '"access_token":"' +
    user.AuthenticationResult["AccessToken"] +
    '",' +
    '"refresh_token":"' +
    user.AuthenticationResult["RefreshToken"] +
    '",' +
    '"expires_in":300,"token_type":"Bearer"}';

  const params = {
    Item: {
      username: {
        S: payload.email.trim().toLowerCase(),
      },
      apti: {
        S: payload.apti,
      },
      authCode: {
        S: authCode,
      },
      state: {
        S: payload.state,
      },
      redirectUri: {
        S: payload.redirectUri,
      },
      tokenString: {
        S: tokenString,
      },
      timestamp: {
        N: `${requestTimeEpoch}`,
      },
      ttl: {
        N: `${parseInt(requestTimeEpoch / 1000 + 3600)}`,
      },
    },
    ReturnConsumedCapacity: "TOTAL",
    TableName: tableNames.authCodeTable,
  };

  const putItemCommand = new PutItemCommand(params);
  const results = await dynamodb.send(putItemCommand);
  console.log(`[Tenant: ${tenantId}] tokens write result:`, results);
};

const genSessionID = async (username, apti, dynamodb, tableNames, tenantId) => {
  console.log(
    `[Tenant: ${tenantId}] generating session id for user:`,
    username,
    " apti:",
    apti,
  );

  const uuid = crypto.randomUUID();
  const timestamp = Date.now();

  const params = {
    Item: {
      uuid: {
        S: uuid,
      },
      username: {
        S: username,
      },
      apti: {
        S: apti,
      },
      otpaddr: {
        S: "FORCE_CHANGE_PASSWORD",
      },
      timestamp: {
        N: `${timestamp}`,
      },
      ttl: {
        N: `${parseInt(timestamp / 1000 + 3600)}`,
      },
    },
    ReturnConsumedCapacity: "TOTAL",
    TableName: tableNames.sessionIdTable,
  };

  const putItemCommand = new PutItemCommand(params);
  const results = await dynamodb.send(putItemCommand);
  console.log(`[Tenant: ${tenantId}] session id creation result:`, results);

  return uuid;
};

const dynamodb = new DynamoDBClient({ region: process.env.AWS_REGION });

// lambda for rest api /oauth2/admininitauth
export const handler = async (event) => {
  console.log(event);

  try {
    // Extract tenant context from request
    const tenantContext = await getTenantContext(event);
    console.log("Tenant context:", tenantContext);

    const payload = JSON.parse(event.body);

    if (validateInputParams(payload)) {
      const cognito = new CognitoIdentityProviderClient({
        region: process.env.AWS_REGION,
      });

      try {
        const user = await getUser(
          payload,
          cognito,
          tenantContext.userPoolId,
          tenantContext.appClientId,
          tenantContext.appSecret,
        );

        // force change password
        if (user.ChallengeName === "NEW_PASSWORD_REQUIRED") {
          const uuid = await genSessionID(
            payload.email,
            payload.apti,
            dynamodb,
            tenantContext.tableNames,
            tenantContext.tenantId,
          );
          const res = { email: payload.email, apti: payload.apti, uuid };
          return createResponse(202, res, tenantContext.tenantId);
        }

        if (user.AuthenticationResult) {
          if (payload.state) {
            const authCode = makeId(32);
            await storeTokens(
              user,
              payload,
              authCode,
              dynamodb,
              event.requestContext.requestTimeEpoch,
              tenantContext.tableNames,
              tenantContext.tenantId,
            );
          }
          const res = { email: payload.email, apti: payload.apti };
          return createResponse(200, res, tenantContext.tenantId);
        }
      } catch (err) {
        console.error(`[Tenant: ${tenantContext.tenantId}] Error:`, err);

        if (
          err.code === "PasswordResetRequiredException" ||
          err.message === "Password reset required for the user"
        ) {
          const uuid = await genSessionID(
            payload.email,
            payload.apti,
            dynamodb,
            tenantContext.tableNames,
            tenantContext.tenantId,
          );
          const res = {
            email: payload.email,
            apti: payload.apti,
            uuid,
            message: "RESET_REQUIRED",
          };
          return createResponse(402, res, tenantContext.tenantId);
        }

        const error = err.message
          ? err
          : { message: "error in password login" };
        return createResponse(400, error, tenantContext.tenantId);
      }
    } else {
      return createResponse(
        500,
        { message: "incoming params error." },
        tenantContext.tenantId,
      );
    }
  } catch (e) {
    console.log("Catch an error: ", e);

    // Try to get tenant ID for error response
    let tenantId = null;
    try {
      const tenantContext = await getTenantContext(event);
      tenantId = tenantContext.tenantId;
    } catch (tenantError) {
      console.log(
        "Could not extract tenant ID for error response:",
        tenantError.message,
      );
    }

    return createResponse(500, { message: "admininitauth error" }, tenantId);
  }
};
